import{_ as e,p as a,q as r,a1 as d}from"./framework-5866ffd3.js";const s={},o=d(`<h1 id="source" tabindex="-1"><a class="header-anchor" href="#source" aria-hidden="true">#</a> source</h1><p>在当前Shell环境中从指定文件读取和执行命令。</p><h3 id="概要" tabindex="-1"><a class="header-anchor" href="#概要" aria-hidden="true">#</a> 概要</h3><p>source filename [arguments]</p><h3 id="主要用途" tabindex="-1"><a class="header-anchor" href="#主要用途" aria-hidden="true">#</a> 主要用途</h3><ul><li>执行文件并从文件中加载变量及函数到执行环境</li></ul><h4 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h4><p>filename：要执行的文件</p><p>arguments（可选）：传递给文件的参数</p><h4 id="返回值" tabindex="-1"><a class="header-anchor" href="#返回值" aria-hidden="true">#</a> 返回值</h4><p>source返回文件最后一个命令的返回值，如果文件不能读取则会失败</p><h4 id="错误用法" tabindex="-1"><a class="header-anchor" href="#错误用法" aria-hidden="true">#</a> 错误用法</h4><ul><li><p>文件在<code>$PATH</code>中找不到。</p></li><li><p>文件未给出。</p></li></ul><h3 id="例子" tabindex="-1"><a class="header-anchor" href="#例子" aria-hidden="true">#</a> 例子</h3><ul><li><p>在一些工具的执行过程中，会把环境变量设置以&quot;export XXX=XXXXXX&quot;或&quot;declare XXX=XXXXXX&quot;的形式导出到 一个文件中，然后用source加载该文件内容到执行环境中。</p></li><li><p>读取和执行/root/.bash_profile文件。</p></li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># source ~/.bash_profile</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="q-a" tabindex="-1"><a class="header-anchor" href="#q-a" aria-hidden="true">#</a> Q&amp;A</h3><p>Q：<code>source</code>和<code>sh</code>在执行文件方面有什么区别？</p><p>A：<code>sh</code>的执行是在子shell中，<code>source</code>会使得被执行文件的变量及函数加载进当前终端环境内（除去函数内local修饰的变量等）；建议您参考<code>export</code>命令的 <strong>知识点</strong> 部分</p><h3 id="注意" tabindex="-1"><a class="header-anchor" href="#注意" aria-hidden="true">#</a> 注意</h3><ol><li>该命令是bash内建命令，相关的帮助信息请查看 <code>help</code> 命令。</li></ol>`,21),c=[o];function i(h,n){return a(),r("div",null,c)}const t=e(s,[["render",i],["__file","source.html.vue"]]);export{t as default};
